#include <bits/stdc++.h>
using namespace std;
struct TreeNode {
    int val;
    TreeNode *left;
    TreeNode *right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

TreeNode* insert(TreeNode* root, int val) {
    if (!root) return new TreeNode(val);
    if (val < root->val) root->left = insert(root->left, val);
    else root->right = insert(root->right, val);
    return root;
}

void inorder(TreeNode* root, vector<int>& res) {
    if (root) {
        inorder(root->left, res);
        res.push_back(root->val);
        inorder(root->right, res);
    }
}

int main() {
    int n;
    cin >> n;
    vector<int> nums(n);
    for (int i = 0; i < n; i++) cin >> nums[i];
    int target;
    cin >> target;

    TreeNode* root = NULL;
    for (int num : nums) root = insert(root, num);

    vector<int> inorder_res;
    inorder(root, inorder_res);

    int left = 0, right = inorder_res.size() - 1;
    while (left < right) {
        long long cur_sum = (long long)inorder_res[left] + inorder_res[right];
        if (cur_sum == target) {
            if (inorder_res[left] != inorder_res[right]) {
                cout << "YES" << endl;
                return 0;
            }
            left++;
            right--;
        } else if (cur_sum < target) left++;
        else right--;
    }
    cout << "NO" << endl;
    return 0;
}
